## Code Examples

### Basic Usage (Current MMS Implementation)

```typescript
// apps/canvas/src/state/viewport.ts
import { createSyncSlice } from '@zazcart/tools';

export const viewportSlice = createSyncSlice({
  id: 'viewport',
  initial: {
    camera: { x: 0, y: 0 },
    canvasSize: { width: 800, height: 600 },
    isPanning: false,
  },
  cache: { policy: 'session' },
  reducers: {
    setCamera(state, payload: { x: number; y: number }) {
      state.camera = payload;
    },
    startPan(state, payload: { panStart; cameraPosAtPanStart }) {
      state.isPanning = true;
      state.panStart = payload.panStart;
      state.cameraPosAtPanStart = payload.cameraPosAtPanStart;
    },
    endPan(state) {
      state.isPanning = false;
    },
  },
});
```

### Machine with Multiple Slices

```typescript
// apps/canvas/src/state/canvas-machine.ts
import { createMachine } from '@zazcart/tools';
import { viewportSlice } from './viewport';
import { interactionSlice } from './interaction';

export const canvasMachine = createMachine({
  id: 'canvas',
  slices: {
    viewport: viewportSlice,
    interaction: interactionSlice,
  },
  context: { userID: null },
  metadata: false,  // High-frequency updates
});

// Typed exports
export const useCanvas = canvasMachine.useMachine;
export const useCanvasSelector = canvasMachine.useSelector;
export const canvasActions = canvasMachine.actions;
export const canvasStore = {
  getState: canvasMachine.getState,
  dispatch: canvasMachine.dispatch,
  subscribe: canvasMachine.subscribe,
};
```

### Usage in React Components

```typescript
// Reading state
const camera = useCanvasSelector(s => s.viewport.camera);

// Dispatching actions
import { canvasStore, canvasActions } from '../state';
canvasStore.dispatch(canvasActions.viewport.setCamera({ x: 100, y: 200 }));

// In animation loops (synchronous read)
function animate() {
  const state = canvasStore.getState();
  const { x, y } = state.viewport.camera;
  // Use values synchronously
  requestAnimationFrame(animate);
}
```

### Async Slice Example

```typescript
const userSlice = createAsyncSlice({
  id: 'user',
  cache: { policy: 'private', ttl: '30m', swr: true },
  context: {
    api: { loadUser: async (id: string) => fetch(`/api/users/${id}`).then(r => r.json()) },
  },
  load: async (userId: string, context) => {
    return context.api.loadUser(userId);
  },
});

// Usage
machine.dispatch(machine.actions.user.load('user-123'));
// ... later after async completion
machine.dispatch(machine.actions.user.success({ id: 'user-123', name: 'John' }));
```

